    def ensure(self) -> NoReturn:
        raise NonIdealStateError(self)


@dataclass(frozen=True)
class GitHubAPIFailed:
    """GitHub API call failed with an error."""

    message: str

    @property
    def error_type(self) -> str:
        return "github-api-failed"

    def ensure(self) -> NoReturn:
